    h->prev = (unsigned short *)malloc(sizeof(*h->prev) * window_size);
    h->hashval = (int *)malloc(sizeof(*h->hashval) * window_size);

    h->same = (unsigned short *)malloc(sizeof(*h->same) * window_size);

    h->head2 = (int *)malloc(sizeof(*h->head2) * 65536);
